def A178544(n):
    if n == 0: return 0
    if n == 2: return 1
    m = (1<<n)-1
    def f(k):
        if k == 1:
            return 1
        else:
            c = f(k-1)
            if 3*(k-1)>n:
                return c*c&m
            else:
                for i in range((1<<k-1)+1,1<<k,2):
                    c = c*i&m
                return c
    c = m
    for k in range(1,n):
        c = c*f(k)&m
    return pow(c,-1,m+1) # _Chai Wah Wu_, Apr 25 2026

